 * Output: Returns 1 if the length is a prime number, otherwise returns 0.
 */
int func0(char *input_str) {
  int str_length = strlen(input_str);
  int divisor;

  // If the string length is less than 2, it cannot be a prime number
  if (str_length < 2)
    return 0;

  // Check divisibility from 2 up to the square root of the string length
  for (divisor = 2; divisor <= str_length / divisor; divisor++) {
    // If the string length is divisible by any number, it is not a prime number
    if (str_length % divisor == 0)
      return 0;
  }

  // If no divisors found, the string length is a prime number
  return 1;
}

